INSERT INTO `learning_objectives` (`id`, `core_content_id`, `content`, `topic_id`, `created_at`, `updated_at`) VALUES
(1, 1, 'Phân biệt được thông tin và dữ liệu, nêu được ví dụ minh hoạ.', 1, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(2, 1, 'Chuyển đổi được giữa các đơn vị lưu trữ thông tin như B, KB, MB,…', 1, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(3, 1, 'Nêu được sự ưu việt của việc lưu trữ, xử lí và truyền thông tin bằng thiết bị số.', 1, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(4, 2, 'Trình bày được những đóng góp cơ bản của tin học đối với xã hội, nêu được ví dụ minh hoạ.', 1, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(5, 2, 'Nêu được ví dụ cụ thể về thiết bị thông minh. Giải thích được vai trò của những thiết bị thông minh đối với sự phát triển của xã hội và cuộc cách mạng công nghiệp 4.0.', 1, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(6, 2, 'Nhận biết được một vài thiết bị số thông dụng khác ngoài máy tính để bàn và máy tính xách tay, giải thích được các thiết bị đó cũng là những hệ thống xử lí thông tin.', 1, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(7, 2, 'Giới thiệu được các thành tựu nổi bật ở một số mốc thời gian để minh hoạ sự phát triển của ngành tin học.', 1, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(8, 3, 'Khởi động được một số thiết bị số thông dụng, sử dụng được các tệp dữ liệu, các chức năng và phần mềm ứng dụng cơ bản cài sẵn trên các thiết bị đó.', 1, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(9, 4, 'Thực hiện được các phép tính cơ bản AND, OR, NOT, giải thích được ứng dụng của hệ nhị phân trong tin học.', 1, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(10, 4, 'Giải thích được sơ lược việc số hoá văn bản, hình ảnh và âm thanh.', 1, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(11, 4, 'Giải thích được sơ lược về chức năng của bảng mã chuẩn quốc tế, ví dụ như Unicode.', 1, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(12, 5, 'Trình bày được những thay đổi về chất lượng cuộc sống, phương thức học tập và làm việc trong xã hội có mạng máy tính được sử dụng phổ biến.', 2, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(13, 5, 'So sánh được mạng LAN và Internet.', 2, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(14, 5, 'Nêu được một số dịch vụ cụ thể mà Điện toán đám mây cung cấp cho người dùng.', 2, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(15, 5, 'Nêu được khái niệm Internet vạn vật (IoT).', 2, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(16, 5, 'Nêu được ví dụ cụ thể về thay đổi trong cuộc sống mà IoT đem lại; phát biểu được ý kiến cá nhân về lợi ích của IoT.', 2, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(17, 6, 'Sử dụng được một số chức năng xử lí thông tin trên máy tính cá nhân và thiết bị số, ví dụ như dịch tự động văn bản hoặc nhận dạng giọng nói.', 2, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(18, 6, 'Khai thác được một số nguồn học liệu mở trên Internet.', 2, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(19, 6, 'Nêu được những nguy cơ và tác hại nếu tham gia các hoạt động trên Internet một cách bất cẩn và thiếu hiểu biết. Trình bày được một số cách phòng tránh các tác hại đó.', 2, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(20, 6, 'Nêu được một số cách phòng vệ khi bị bắt nạt trên mạng.', 2, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(21, 6, 'Biết cách tự bảo vệ dữ liệu cá nhân.', 2, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(22, 6, 'Trình bày được sơ lược về phần mềm độc hại. Sử dụng được một số công cụ thông dụng để ngăn ngừa và diệt phần mềm độc hại.', 2, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(23, 7, 'Nêu được một số vấn đề nảy sinh về pháp luật, đạo đức và văn hóa khi giao tiếp qua mạng trên diện rộng.', 4, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(24, 7, 'Nêu được ví dụ minh họa sự vi phạm bản quyền thông tin và sản phẩm số; qua ví dụ đó giải thích được sự vi phạm đã diễn ra thế nào và có thể dẫn tới hậu quả gì.', 4, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(25, 7, 'Trình bày và giải thích được một số nội dung cơ bản của Luật Công nghệ thông tin, Nghị định về quản lí, cung cấp, sử dụng các sản phẩm và dịch vụ CNTT, Luật An ninh mạng; nêu được ví dụ minh họa.', 4, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(26, 7, 'Giải thích được một số khía cạnh pháp lí của vấn đề bản quyền, của việc sở hữu, sử dụng và trao đổi thông tin trong môi trường số; nêu được ví dụ minh họa.', 4, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(27, 7, 'Vận dụng được Luật và Nghị định nêu trên để xác định được tính hợp pháp của một hành vi nào đó trong lĩnh vực quản lí, cung cấp, sử dụng các sản phẩm, dịch vụ Công nghệ thông tin.', 4, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(28, 7, 'Nêu được ví dụ về những tác hại của việc chia sẻ và phổ biến thông tin một cách bất cẩn. Nêu được một vài biện pháp đơn giản và thông dụng nhằm nâng cao tính an toàn và hợp pháp.', 4, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(29, 8, 'Sử dụng được một số chức năng cơ bản của phần mềm thiết kế đồ hoạ.', 5, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(30, 8, 'Tạo được sản phẩm số đơn giản, hữu ích và thực tế như thiết kế logo, tạo banner, topic quảng cáo, băng-rôn, áp phích, poster và thiệp chúc mừng, …', 5, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(31, 9, 'Viết và thực hiện được một vài chương trình có sử dụng hằng, biến, các cấu trúc điều khiển, các toán tử, các kiểu dữ liệu chuẩn và mảng, các câu lệnh vào – ra.', 6, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(32, 10, 'Viết được chương trình có sử dụng chương trình con trong thư viện chuẩn.', 6, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(33, 10, 'Viết được chương trình con biểu diễn một thuật toán đơn giản và viết được chương trình có sử dụng chương trình con đó.', 6, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(34, 11, 'Đọc hiểu được chương trình đơn giản.', 6, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(35, 11, 'Kiểm thử và gỡ lỗi được chương trình.', 6, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(36, 11, 'Viết và thực hiện được chương trình giải quyết bài toán đơn giản có vận dụng kiến thức liên môn.', 6, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(37, 12, 'Trình bày được thông tin hướng nghiệp về nhóm nghề Thiết kế và Lập trình thông qua phân tích nghiệp vụ của một số nghề điển hình.', 7, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(38, 12, 'Tự tìm kiếm và khai thác được thông tin hướng nghiệp về một vài ngành nghề khác trong lĩnh vực tin học.', 7, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(39, 12, 'Giao lưu được với bạn bè qua các kênh truyền thông tin số để tham khảo và trao đổi ý kiến về những thông tin trên.', 7, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(40, 13, 'Trình bày được sơ lược lịch sử phát triển của hai hệ điều hành thông dụng cho PC.', 1, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(41, 13, 'Sử dụng được một số chức năng cơ bản của một trong hai hệ điều hành đó.', 1, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(42, 13, 'Trình bày được vài nét chính về một hệ điều hành thông dụng cho thiết bị di động và sử dụng được một số tiện ích cơ bản.', 1, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(43, 13, 'Trình bày được một cách khái quát mối quan hệ giữa phần cứng, hệ điều hành và phần mềm ứng dụng.', 1, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(44, 14, 'Trình bày được một số khái niệm có liên quan tới phần mềm nguồn mở như quyền phần mềm, giấy phép công cộng, phần mềm miễn phí.', 1, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(45, 14, 'So sánh được phần mềm nguồn mở với phần mềm thương mại (nguồn đóng).', 1, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(46, 14, 'Nêu được vai trò của phần mềm nguồn mở và phần mềm thương mại đối với sự phát triển của CNTT.', 1, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(47, 14, 'Nêu được tên một số phần mềm soạn thảo văn bản, trình chiếu nguồn mở.', 1, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(48, 14, 'Sử dụng được một số tiện ích có sẵn của hệ điều hành để nâng cao hiệu suất sử dụng máy tính.', 1, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(49, 14, 'Kích hoạt và sử dụng được một vài chức năng cơ bản của một phần mềm soạn thảo văn bản, bảng tính, trình chiếu chạy trên Internet.', 1, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(50, 15, 'Nhận diện được hình dạng, mô tả được chức năng của các bộ phận chính bên trong máy tính như CPU, RAM và các thiết bị lưu trữ.', 1, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(51, 15, 'Nêu được tên và giải thích được đơn vị đo dung lượng của các thiết bị lưu trữ như GB, TB.', 1, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(52, 15, 'Nhận biết được sơ đồ cấu trúc các mạch logic AND, OR, NOT; giải thích được vai trò của các mạch logic đó trong thực hiện các tính toán nhị phân.', 1, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(53, 16, 'Tuỳ chỉnh được một vài chức năng cơ bản của máy tính và các thiết bị vào – ra thông dụng.', 1, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(54, 16, 'Đọc hiểu được một số điểm chính trong tài liệu hướng dẫn về thiết bị số thông dụng; thực hiện được một số thông số định dạng tối ưu.', 1, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(55, 16, 'Đọc hiểu và giải thích được một số thông số cơ bản như kích thước màn hình, CPU, RAM, dung lượng lưu trữ, độ phân giải camera,…', 1, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(56, 16, 'Biết được cách kết nối các bộ phận như bàn phím, bàn chuột, màn hình của máy tính với nhau.', 1, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(57, 16, 'Biết được cách kết nối PC với các thiết bị số thông dụng như máy in, điện thoại thông minh và máy ảnh số.', 1, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(58, 17, 'Sử dụng được một số công cụ trực tuyến như Google Drive hay Dropbox…', 3, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(59, 17, 'Sử dụng được máy tìm kiếm trên PC và thiết bị số thông minh để tìm kiếm thông tin bằng cách gõ từ khoá hoặc bằng tiếng nói.', 3, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(60, 17, 'Xác lập được các lựa chọn theo tiêu chí tìm kiếm để nâng cao hiệu quả tìm kiếm thông tin.', 3, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(61, 17, 'Sử dụng được những chức năng nâng cao của dịch vụ mạng xã hội.', 3, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(62, 17, 'Biết cách phân loại và đánh dấu các email.', 3, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
