(69, 21, 'Nhận biết được nhu cầu lưu trữ dữ liệu và khai thác thông tin cho bài toán quản lí.', 6, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(70, 21, 'Diễn đạt được khái niệm hệ Cơ sở dữ liệu; các khái niệm cơ bản trong mô hình Cơ sở dữ liệu quan hệ như bảng, khóa, khóa ngoài, truy vấn, cập nhật dữ liệu.', 6, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(71, 21, 'Nêu được những khái niệm cơ bản của Cơ sở dữ liệu; giải thích được các khái niệm đó qua ví dụ minh họa.', 6, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(72, 21, 'Phân biệt được hai loại kiến trúc hệ Cơ sở dữ liệu là tập trung và phân tán.', 6, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(73, 21, 'Nêu được tầm quan trọng và một số biện pháp bảo mật hệ Cơ sở dữ liệu.', 6, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(74, 22, 'Tạo được các bảng và chỉ định được khóa cho mỗi bảng; thiết lập được mối quan hệ giữa các bảng qua việc chỉ định khóa ngoài.', 6, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
