(76, 22, 'Nêu được một vài tổ chức cần ứng dụng Cơ sở dữ liệu để quản lí hoạt động của mình.', 6, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(77, 22, 'Thể hiện được tính cẩn thận, chăm chỉ, trách nhiệm trong việc lưu trữ và quản lí dữ liệu.', 6, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(78, 23, 'Sử dụng được các truy vấn để tìm kiếm và kết xuất thông tin từ Cơ sở dữ liệu.', 6, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(79, 23, 'Nêu được một vài nhận xét so sánh kết quả thực hành với một phần mềm quản lí do giáo viên giới thiệu hoặc đã từng biết.', 6, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(80, 23, 'Giải thích được tính ưu việt của việc quản lí dữ liệu một cách khoa học nhờ ứng dụng Cơ sở dữ liệu.', 6, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(81, 23, 'Tìm hiểu được thêm một vài chức năng của hệ Quản trị cơ sở dữ liệu.', 6, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
