(86, 25, 'Trình bày được sơ lược khái niệm độ phức tạp thời gian của thuật toán và phép toán tích cực. Nêu được ví dụ minh họa.', 6, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(87, 25, 'Vận dụng được những quy tắc thực hành xác định độ phức tạp thời gian của một số thuật toán, chương trình đã biết.', 6, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(88, 26, 'Giải thích và vận dụng được phương pháp làm mịn dần trong lập trình.', 6, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(89, 26, 'Giải thích và vận dụng được phương pháp thiết kế chương trình thành các mô đun cho một bài toán cụ thể.', 6, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(90, 26, 'Nhận biết được lợi ích của phương pháp nêu trên trong việc hỗ trợ làm việc đồng thời, dễ dàng bảo trì, phát triển chương trình và tái sử dụng mô đun.', 6, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(91, 27, 'Trình bày được cấu trúc dữ liệu mảng (một và hai chiều) và danh sách liên kết.', 6, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(92, 27, 'Tạo được một thư viện nhỏ và viết được chương trình có sử dụng thư viện vừa tạo ra.', 6, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(93, 27, 'Viết được chương trình vận dụng những kiến thức tích hợp liên môn để giải quyết vấn đề.', 6, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(94, 28, 'Trình bày được thông tin hướng nghiệp về nghề Quản trị cơ sở dữ liệu.', 7, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(95, 28, 'Tự tìm kiếm và khai thác được thông tin hướng nghiệp về một vài ngành nghề khác trong lĩnh vực tin học.', 7, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(96, 28, 'Giao lưu được với bạn bè qua các kênh truyền thông số để tham khảo và trao đổi ý kiến.', 7, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(97, 29, 'Giải thích được sơ lược về khái niệm Trí tuệ nhân tạo (AI – Artificial Intelligence).', 1, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(98, 29, 'Nêu được ví dụ minh họa cho một số ứng dụng điển hình của AI như điều khiển tự động, chẩn đoán bệnh, nhận dạng chữ viết tay...', 1, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(99, 29, 'Chỉ ra được một số lĩnh vực của khoa học công nghệ và đời sống đã và đang phát triển mạnh mẽ dựa trên những thành tựu lớn của AI.', 1, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(100, 29, 'Nêu được ví dụ để thấy một hệ thống AI có tri thức, có khả năng suy luận và khả năng học.', 1, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(101, 29, 'Nêu được một cảnh báo về sự phát triển của AI trong tương lai.', 1, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(102, 30, 'Kết nối được PC với các thiết bị số thông dụng như điện thoại di động, ti vi có khả năng kết nối Internet, vòng đeo tay thông minh, thiết bị thực tế ảo,…', 1, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(103, 31, 'Nêu được chức năng chính của một số thiết bị mạng thông dụng, ví dụ như Access Point, Switch, Modem. Kết nối được các thiết bị đó với PC.', 2, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(104, 31, 'Mô tả sơ lược vai trò và chức năng của giao thức mạng nói chung và giao thức TCP/IP nói riêng.', 2, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(105, 32, 'Sử dụng được các chức năng mạng của hệ điều hành để chia sẻ tài nguyên.', 2, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(106, 33, 'Kết nối được thiết bị di động vào mạng máy tính trong điều kiện phần cứng và phần mềm đã được chuẩn bị đầy đủ.', 2, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(107, 34, 'Nhận diện và phân biệt được chức năng các thiết bị mạng như Server, Switch, Modem, Access Point, cáp mạng.', 2, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(108, 34, 'Nêu được khái niệm và ứng dụng của một số loại đường truyền hữu tuyến và vô tuyến thông dụng.', 2, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(109, 34, 'Trình bày và giải thích sơ lược được việc thiết kế mạng LAN cho một tổ chức nhỏ, ví dụ cho một trường phổ thông.', 2, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(110, 35, 'Phân tích được ưu và nhược điểm về giao tiếp ảo qua các ví dụ cụ thể.', 4, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(111, 35, 'Phân tích được tính nhân văn trong ứng xử ở một số tình huống tham gia thế giới ảo.', 4, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(112, 36, 'Sử dụng được một số chức năng cơ bản của phần mềm tạo trang web.', 5, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(113, 36, 'Tạo được một trang web tĩnh đơn giản gồm một vài thành phần cơ bản: Menu, Content.', 5, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(114, 37, 'Hiểu và giải thích được cấu trúc của một trang web dưới dạng HTML.', 6, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(115, 37, 'Sử dụng được các thẻ HTML để trình bày trang web, bao gồm: Định dạng văn bản, phông chữ, tạo liên kết, danh sách.', 6, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(116, 37, 'Đưa các tệp dữ liệu đa phương tiện vào trang web (ví dụ: ảnh, âm thanh, video).', 6, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(117, 37, 'Tạo bảng và khung (frame). Tạo biểu mẫu (form).', 6, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(118, 38, 'Hiểu và sử dụng được một số thuộc tính cơ bản của CSS như màu sắc, phông chữ, nền, đường viền, kích cỡ,…', 6, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(119, 38, 'Sử dụng được các yếu tố của vùng chọn (selector) như class, id, tag,…', 6, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(120, 38, 'Sử dụng được CSS làm trang web đẹp, đa dạng và sinh động hơn.', 6, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(121, 39, 'Nêu được sơ lược về mục tiêu và một số thành tựu của Khoa học dữ liệu; nêu được ví dụ minh họa.', 6, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(122, 39, 'Biết được vai trò của máy tính đối với sự phát triển của Khoa học dữ liệu.', 6, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(123, 39, 'Biết được tính ưu việt trong việc sử dụng máy tính và thuật toán hiệu quả để xử lí khối dữ liệu lớn; nêu được ví dụ minh họa.', 6, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(124, 39, 'Nêu được trải nghiệm của bản thân trong việc trích rút thông tin và tri thức từ dữ liệu đã có.', 6, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(125, 40, 'Giải thích được sơ lược về khái niệm Học máy.', 6, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(126, 40, 'Nêu được vai trò của Học máy trong những công việc như lọc thư rác, chẩn đoán bệnh, phân tích thị trường, nhận dạng tiếng nói và chữ viết, dịch tự động,…', 6, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(127, 41, 'Nêu được một vài lĩnh vực trong cuộc sống có sử dụng kĩ thuật mô phỏng.', 6, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(128, 41, 'Nêu được một vài vấn đề thực tế mà ở đó có thể cần dùng kĩ thuật mô phỏng để giải quyết.', 6, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(129, 41, 'Sử dụng và giải thích được các bước cơ bản của một phần mềm mô phỏng.', 6, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(130, 42, 'Trình bày được thông tin hướng nghiệp nhóm nghề Dịch vụ và Quản trị theo các yếu tố: sơ lược công việc, yêu cầu kiến thức, ngành học liên quan, nhu cầu nhân lực.', 7, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(131, 42, 'Tự tìm kiếm và khai thác được thông tin hướng nghiệp qua các chương trình đào tạo, thông báo tuyển dụng nhân lực về một vài ngành nghề khác trong lĩnh vực tin học.', 7, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(132, 42, 'Giao lưu được với bạn bè qua các kênh truyền thông số để tham khảo và trao đổi ý kiến về những thông tin trên.', 7, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(133, 43, 'Nêu được tên một số ngành nghề và lĩnh vực có sử dụng nhân lực tin học, đồng thời giải thích được vai trò và công việc của chuyên viên tin học trong một số ngành nghề.', 7, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(134, 43, 'Tìm hiểu được thông tin ngành đào tạo của một số cơ sở đào tạo Công nghệ thông tin.', 7, '2026-02-25 15:23:59', '2026-02-25 15:23:59'),
(135, 44, 'Phân tích tính phức tạp của các cuộc tấn công mạng và nhu cầu nhân lực bảo mật.', 3, '2026-02-25 15:23:59', '2026-02-25 15:23:59');
