INSERT INTO `questions` (`id`, `user_id`, `grade`, `orientation`, `content`, `type`, `source`, `parent_id`, `topic_id`, `competency_id`, `cognitive_level_id`, `created_at`, `updated_at`, `learning_objective_id`, `core_content_id`) VALUES
(1, 5, 12, 'chung', 'Khả năng hiểu ngôn ngữ của Trí tuệ nhân tạo không thể hiện trong hệ thống nào sau đây?', 'single_choice', 'thpt_2025', NULL, 1, 1, 2, '2026-02-25 15:23:59', '2026-03-27 12:03:42', 98, 29),
(2, 5, 12, 'chung', 'Người quản trị mạng thực hiện công việc chính nào sau đây?', 'single_choice', 'thpt_2025', NULL, 7, 3, 1, '2026-02-25 15:23:59', '2026-03-27 12:03:42', 130, 42),
(3, 5, 12, 'chung', 'Phương án nào sau đây chỉ ra lý do chủ yếu dẫn tới nhu cầu gia tăng về số lượng chuyên gia bảo mật hệ thống thông tin?', 'single_choice', 'thpt_2025', NULL, 3, 3, 2, '2026-02-25 15:23:59', '2026-03-27 12:03:42', 135, 44),
(4, 5, 12, 'chung', 'Trong lĩnh vực y tế, Trí tuệ nhân tạo được ứng dụng phổ biến trong hệ thống nào sau đây?', 'single_choice', 'thpt_2025', NULL, 1, 1, 2, '2026-02-25 15:23:59', '2026-03-27 12:03:42', 99, 29),
(5, 5, 12, 'chung', 'Thiết bị nào có chức năng chính là thiết lập kênh kết nối giữa các thiết bị trong mạng LAN có dây?', 'single_choice', 'thpt_2025', NULL, 2, 3, 1, '2026-02-25 15:23:59', '2026-03-27 12:03:42', 103, 31),
(6, 5, 12, 'chung', 'Một công ty có hai chi nhánh cách nhau khoảng 10 km, mỗi chi nhánh có một mạng LAN riêng. Thiết bị nào phù hợp nhất để kết nối hai mạng này?', 'single_choice', 'thpt_2025', NULL, 2, 3, 2, '2026-02-25 15:23:59', '2026-03-27 12:03:42', 103, 31),
(7, 5, 12, 'chung', 'Đoạn mã CSS nào thiết lập đường viền dày 3 pixel, kiểu nét đứt?', 'single_choice', 'thpt_2025', NULL, 6, 3, 1, '2026-02-25 15:23:59', '2026-03-27 12:03:42', 118, 38),
(8, 5, 10, 'chung', '<p>Xét đoạn chương trình Python sau:</p><img src=\"/storage/questions/cau8.png\" style=\"max-width: 100%; border-radius: 8px; margin: 10px 0;\"><p>Phương án nào sau đây chỉ ra đúng số lần lặp của câu lệnh while ở Dòng 2?</p>', 'single_choice', 'thpt_2025', NULL, 6, 3, 2, '2026-02-25 15:23:59', '2026-03-27 12:03:42', 34, 11),
(9, 5, 10, 'chung', '<p>Cho đoạn chương trình:</p><img src=\"/storage/questions/cau9.png\" style=\"max-width: 100%; border-radius: 8px; margin: 10px 0;\"><p>Sau khi thực hiện đoạn chương trình trên, kí tự nào sau đây được hiển thị trên màn hình?</p>', 'single_choice', 'thpt_2025', NULL, 6, 3, 3, '2026-02-25 15:23:59', '2026-03-27 12:03:42', 34, 11),
(10, 5, 12, 'chung', 'Trong bộ giao thức TCP/IP, giao thức IP đảm nhận vai trò nào?', 'single_choice', 'thpt_2025', NULL, 2, 1, 1, '2026-02-25 15:23:59', '2026-03-27 12:03:42', 104, 31),
(11, 5, 12, 'chung', 'Đoạn mã HTML nào định dạng “TN THPT 2025” in đậm, riêng số 2025 in nghiêng?', 'single_choice', 'thpt_2025', NULL, 6, 3, 2, '2026-02-25 15:23:59', '2026-03-27 12:03:42', 115, 37),
(12, 5, 12, 'chung', 'Hành vi nào không phù hợp với đạo đức trong môi trường số?', 'single_choice', 'thpt_2025', NULL, 4, 2, 1, '2026-02-25 15:23:59', '2026-03-27 12:03:42', 111, 35),
(13, 5, 12, 'chung', 'Thẻ HTML dùng để tạo danh sách có thứ tự là:', 'single_choice', 'thpt_2025', NULL, 6, 3, 1, '2026-02-25 15:23:59', '2026-03-27 12:03:42', 114, 37),
(14, 5, 12, 'chung', 'Thuộc tính CSS dùng để thiết lập cỡ chữ là:', 'single_choice', 'thpt_2025', NULL, 6, 3, 1, '2026-02-25 15:23:59', '2026-03-27 12:03:42', 118, 38),
(15, 5, 12, 'chung', '<p>Xét mã HTML/CSS sau, dòng chữ hiển thị như thế nào?</p><img src=\"/storage/questions/cau15.png\" style=\"max-width: 100%; border-radius: 8px; margin: 10px 0;\">', 'single_choice', 'thpt_2025', NULL, 6, 3, 2, '2026-02-25 15:23:59', '2026-03-27 12:03:42', 119, 38),
(16, 5, 12, 'chung', 'Tiêu đề của trang web được khai báo trong thẻ nào?', 'single_choice', 'thpt_2025', NULL, 6, 3, 1, '2026-02-25 15:23:59', '2026-03-27 12:03:42', 114, 37),
(17, 5, 12, 'chung', 'Đoạn mã CSS nào thiết lập hình ảnh và văn bản hiển thị theo khối?', 'single_choice', 'thpt_2025', NULL, 6, 3, 1, '2026-02-25 15:23:59', '2026-03-27 12:03:42', 118, 38),
(18, 5, 12, 'chung', 'Người sửa chữa và bảo trì máy tính cần kiến thức chủ yếu về:', 'single_choice', 'thpt_2025', NULL, 7, 3, 1, '2026-02-25 15:23:59', '2026-03-27 12:03:42', 130, 42),
(19, 5, 12, 'chung', 'Hành động nào không thể hiện tính nhân văn trên không gian mạng khi biết tin thiên tai?', 'single_choice', 'thpt_2025', NULL, 4, 2, 2, '2026-02-25 15:23:59', '2026-03-27 12:03:42', 111, 35),
(20, 5, 12, 'chung', 'Hành động nào không an toàn khi được mời “việc nhẹ lương cao” qua mạng?', 'single_choice', 'thpt_2025', NULL, 4, 2, 2, '2026-02-25 15:23:59', '2026-03-27 12:03:42', 110, 35),
(21, 5, 12, 'chung', '<p>Bảng HTML sau có bao nhiêu hàng và cột?</p><img src=\"/storage/questions/cau21.png\" style=\"max-width: 100%; border-radius: 8px; margin: 10px 0;\">', 'single_choice', 'thpt_2025', NULL, 6, 3, 2, '2026-02-25 15:23:59', '2026-03-27 12:03:42', 117, 37),
(22, 5, 12, 'chung', 'Lĩnh vực tin học giúp máy tính ngày càng thông minh như con người là:', 'single_choice', 'thpt_2025', NULL, 1, 1, 1, '2026-02-25 15:23:59', '2026-03-27 12:03:42', 97, 29),
(23, 5, 12, 'chung', 'Cách ứng xử phù hợp với kết quả do Trí tuệ nhân tạo tạo ra là:', 'single_choice', 'thpt_2025', NULL, 1, 1, 2, '2026-02-25 15:23:59', '2026-03-27 12:03:42', 101, 29),
(24, 5, 12, 'chung', 'Router có chức năng chính là:', 'single_choice', 'thpt_2025', NULL, 2, 3, 1, '2026-02-25 15:23:59', '2026-03-27 12:03:42', 103, 31),
(25, 5, 12, 'chung', 'Tòa nhà của một công ty có một số phòng làm việc. Mỗi phòng có không quá 10 máy tính, được kết nối với nhau thông qua Switch tạo thành một mạng LAN. Công ty cần kết nối các mạng LAN này với nhau để tạo thành một mạng cục bộ duy nhất. Sau khi thảo luận, một số nhân viên đưa ra các nhận định:', 'true_false_group', 'thpt_2025', NULL, 2, 3, NULL, '2026-02-25 15:23:59', '2026-03-27 12:03:42', 109, 34),
(26, 5, 12, 'chung', 'a) Mạng cục bộ của công ty là mạng WAN.', '', 'thpt_2025', 25, 2, 3, 1, '2026-02-25 15:23:59', '2026-02-25 15:23:59', 109, 34),
(27, 5, 12, 'chung', 'b) Có thể sử dụng Switch loại 16 cổng để kết nối các máy tính trong mỗi phòng làm việc.', '', 'thpt_2025', 25, 2, 3, 2, '2026-02-25 15:23:59', '2026-02-25 15:23:59', 109, 34),
(28, 5, 12, 'chung', 'c) Để máy tính trong các phòng làm việc truy cập được Internet thì chỉ cần lắp đặt thêm một Modem mà không cần phải đăng ký với nhà cung cấp dịch vụ Internet.', '', 'thpt_2025', 25, 2, 3, 2, '2026-02-25 15:23:59', '2026-02-25 15:23:59', 109, 34),
(29, 5, 12, 'chung', 'd) Để các nhân viên có thể sử dụng điện thoại thông minh kết nối được vào mạng cục bộ của công ty qua Wi-Fi, có thể lắp đặt cho mỗi phòng một Access Point và kết nối thiết bị này với Switch ở phòng đó.', '', 'thpt_2025', 25, 2, 3, 3, '2026-02-25 15:23:59', '2026-02-25 15:23:59', 109, 34),
(30, 5, 11, 'chung', 'Dữ liệu về dân số nước ta từ năm 2019 đến năm 2023 có trong niên giám số liệu thống kê. Để lưu trữ, có thể tạo CSDL với các bảng: KHUVUC (maKV, tenKV); TINH (maTinh, maKV, tenTinh); DANSO (maTinh, nam, danSoTB). Học sinh đưa ra ý kiến:', 'true_false_group', 'thpt_2025', NULL, 6, 3, NULL, '2026-02-25 15:23:59', '2026-03-27 12:03:42', 70, 21),
(31, 5, 11, 'chung', 'a) Trường maKV là khóa ngoài của bảng KHUVUC.', '', 'thpt_2025', 30, 6, 3, 1, '2026-02-25 15:23:59', '2026-02-25 15:23:59', 70, 21),
(32, 5, 11, 'chung', 'b) Nhóm hai trường maTinh và nam là khóa chính của bảng DANSO.', '', 'thpt_2025', 30, 6, 3, 2, '2026-02-25 15:23:59', '2026-02-25 15:23:59', 70, 21),
(33, 5, 11, 'chung', 'c) Chỉ cần liên kết hai bảng TINH và DANSO theo khóa maTình là có thể kết xuất được thông tin đầy đủ gồm: tên tỉnh, tên khu vực, năm và dân số trung bình của năm.', '', 'thpt_2025', 30, 6, 3, 2, '2026-02-25 15:23:59', '2026-02-25 15:23:59', 70, 21),
(34, 5, 11, 'chung', 'd) Để đưa ra được thông tin gồm tên tỉnh, năm và dân số trung bình của năm 2020, có thể thực hiện truy vấn với điều kiện DANSO.nam = 2020.', '', 'thpt_2025', 30, 6, 3, 3, '2026-02-25 15:23:59', '2026-02-25 15:23:59', 70, 21),
(35, 5, 11, 'cs', 'Hội chứng FOMO là cảm giác lo âu, tiếc nuối... Một công ty xây dựng hệ thống AI dự đoán, thu thập dữ liệu từ hơn 10000 người làm dữ liệu huấn luyện. Kết quả tỉ lệ mắc là 35% và chưa mắc là 65%. Nhân viên đưa ra nhận định:', 'true_false_group', 'thpt_2025', NULL, 5, 3, NULL, '2026-02-25 15:23:59', '2026-03-27 12:03:42', 125, 40),
(36, 5, 11, 'cs', 'a) Thông tin mắc và chưa mắc Hội chứng của mỗi người có thể được sử dụng làm nhãn của dữ liệu huấn luyện mô hình.', '', 'thpt_2025', 35, 5, 3, 2, '2026-02-25 15:23:59', '2026-02-25 15:23:59', 125, 40),
(37, 5, 11, 'cs', 'b) Không cần sử dụng các phương pháp tiền xử lý để làm sạch tập dữ liệu đã thu thập nói trên trước khi đưa vào huấn luyện mô hình.', '', 'thpt_2025', 35, 5, 3, 2, '2026-02-25 15:23:59', '2026-02-25 15:23:59', 125, 40),
(38, 5, 11, 'cs', 'c) Mô hình học máy phù hợp nhất được sử dụng để xây dựng hệ thống dự đoán trong tình huống này là mô hình Học có giám sát.', '', 'thpt_2025', 35, 5, 3, 1, '2026-02-25 15:23:59', '2026-02-25 15:23:59', 125, 40),
(39, 5, 11, 'cs', 'd) Khi xuất hiện biểu hiện lo âu, tiếc nuối, người ta chỉ cần sử dụng hệ thống dự đoán của công ty nói trên để biết được chính xác mình có mắc Hội chứng hay không.', '', 'thpt_2025', 35, 5, 3, 3, '2026-02-25 15:23:59', '2026-02-25 15:23:59', 125, 40),
(40, 5, 11, 'cs', '<p>Cho hàm sau đây được viết bằng ngôn ngữ lập trình Python và C++:</p><img src=\"/storage/questions/cau28.png\" style=\"max-width: 100%; border-radius: 8px; margin: 10px 0;\"><p>Học sinh đã nêu các ý kiến sau:</p>', 'true_false_group', 'thpt_2025', NULL, 6, 3, NULL, '2026-02-25 15:23:59', '2026-03-27 12:03:42', 91, 27),
(41, 5, 11, 'cs', 'a) Mảng A biểu diễn cấu trúc dữ liệu ngăn xếp (Stack).', '', 'thpt_2025', 40, 6, 3, 1, '2026-02-25 15:23:59', '2026-02-25 15:23:59', 91, 27),
(42, 5, 11, 'cs', 'b) Nếu dữ liệu đầu vào là mảng A gồm n phần tử đã được sắp xếp theo chiều không giảm thì các câu lệnh tại Dòng 6 và Dòng 7 được thực hiện n lần.', '', 'thpt_2025', 40, 6, 3, 2, '2026-02-25 15:23:59', '2026-02-25 15:23:59', 91, 27),
(43, 5, 11, 'cs', 'c) Nếu dữ liệu đầu vào là n = 6 và mảng A là (6, 4, 2, 1, 3, 5) thì sau khi câu lệnh for tại Dòng 2 thực hiện lần lặp thứ 2, giá trị của mảng A là (2, 4, 6, 1, 3, 5).', '', 'thpt_2025', 40, 6, 3, 3, '2026-02-25 15:23:59', '2026-02-25 15:23:59', 91, 27),
(44, 5, 11, 'cs', 'd) Nếu dữ liệu đầu vào là n = 7 và mảng A là (8, 6, 4, 2, 3, 5, 7) thì hàm trả về giá trị 6.5.', '', 'thpt_2025', 40, 6, 3, 2, '2026-02-25 15:23:59', '2026-02-25 15:23:59', 91, 27),
(45, 5, 12, 'ict', 'Một trường phổ thông muốn sử dụng phần mềm xây dựng website thông tin CLB. Website có: Phần đầu chứa logo; thanh banner chứa hình ảnh hoạt động; thanh điều hướng gồm ba mục chính. Học sinh đưa ra ý kiến:', 'true_false_group', 'thpt_2025', NULL, 5, 3, NULL, '2026-02-25 15:23:59', '2026-03-27 12:03:42', 113, 36),
(46, 5, 12, 'ict', 'a) Phần mềm tạo trang web có sẵn mẫu bố cục trang web để thiết kế các phần cho website của trường.', '', 'thpt_2025', 45, 5, 3, 1, '2026-02-25 15:23:59', '2026-02-25 15:23:59', 113, 36),
(47, 5, 12, 'ict', 'b) Phần mềm tạo trang web cho phép thay thế ảnh có sẵn của mẫu bằng ảnh về hoạt động của các CLB.', '', 'thpt_2025', 45, 5, 3, 2, '2026-02-25 15:23:59', '2026-02-25 15:23:59', 113, 36),
(48, 5, 12, 'ict', 'c) Các mục con có nhãn là tên các CLB bắt buộc phải hiển thị trên thanh điều hướng của trang chủ.', '', 'thpt_2025', 45, 5, 3, 2, '2026-02-25 15:23:59', '2026-02-25 15:23:59', 113, 36),
(49, 5, 12, 'ict', 'd) Để có thể xem được video về hoạt động của các CLB trên website, phải đồng thời tải video lên máy chủ và nhúng liên kết YouTube.', '', 'thpt_2025', 45, 5, 3, 3, '2026-02-25 15:23:59', '2026-02-25 15:23:59', 113, 36),
(50, 5, 11, 'ict', 'Cần tạo cơ sở dữ liệu với các bảng: KHUVUC (maKV, tenKV); DIAPHUONG (maDP, tenDP, maKV); DAUTU (maDP, nam, tongVon). Học sinh đưa ra ý kiến:', 'true_false_group', 'thpt_2025', NULL, 6, 3, NULL, '2026-02-25 15:23:59', '2026-03-27 12:03:42', 78, 23),
(51, 5, 11, 'ict', 'a) Phần mềm bảng tính có thể lưu trữ cơ sở dữ liệu đã nêu trong một trang tính duy nhất.', '', 'thpt_2025', 50, 6, 3, 2, '2026-02-25 15:23:59', '2026-02-25 15:23:59', 78, 23),
(52, 5, 11, 'ict', 'b) Khi tạo bảng DAUTU trong phần mềm quản trị cơ sở dữ liệu, chọn trường maDP rồi thiết lập trường này làm khóa chính của bảng.', '', 'thpt_2025', 50, 6, 3, 1, '2026-02-25 15:23:59', '2026-02-25 15:23:59', 78, 23),
(53, 5, 11, 'ict', 'c) Mối quan hệ của 3 bảng được thiết lập dựa trên việc liên kết từ bảng KHUVUC đến bảng DIAPHUONG và liên kết từ bảng KHUVUC đến bảng DAUTU.', '', 'thpt_2025', 50, 6, 3, 2, '2026-02-25 15:23:59', '2026-02-25 15:23:59', 78, 23),
(54, 5, 11, 'ict', 'd) Để đưa ra thông tin gồm tên khu vực, địa phương, năm, tổng vốn, có thể dùng câu lệnh SELECT kết hợp INNER JOIN.', '', 'thpt_2025', 50, 6, 3, 3, '2026-02-25 15:23:59', '2026-02-25 15:23:59', 78, 23),
(55, 1, 12, 'chung', '<p>Các ứng dụng nào sau đây được phát triển nhờ thành tựu của Trí tuệ nhân tạo (AI)?</p>', 'single_choice', 'user', NULL, 1, 1, 1, '2026-03-23 13:06:43', '2026-03-23 13:06:43', 97, 29),
(62, 1, 12, 'chung', '<p>Tình huống nào sau đây không có ứng dụng của AI trong các hoạt động thương mại điện tử?</p>', 'single_choice', 'user', NULL, 1, 1, 1, '2026-03-23 13:59:50', '2026-03-23 13:59:50', 97, 29),
(63, 12, 12, 'chung', '<p>Tình huống nào sau đây không là ứng dụng của Trí tuệ nhân tạo (AI) trong nhận dạng chữ viết tay, tiếng nói và khuôn mặt?</p>', 'single_choice', 'user', NULL, 1, 1, 1, '2026-03-23 14:03:20', '2026-03-23 14:03:20', 97, 29),
(64, 12, 12, 'chung', '<p>Giao thức nào sau đây nhằm quản lí việc truyền dữ liệu giữa các thiết bị?</p>', 'single_choice', 'user', NULL, 6, 1, 1, '2026-03-25 04:13:07', '2026-03-25 04:13:07', 115, 37),
(65, 1, 10, 'chung', '<p>Cho đoạn chương trình:&nbsp;</p><p>j = 0&nbsp;</p><p>for i in range(5):&nbsp;</p><p>&nbsp; &nbsp; j = j + i print(j)&nbsp;</p><p>Sau khi thực hiện chương trình giá trị của biến j bằng bao nhiêu?</p>', 'single_choice', 'user', NULL, 6, 1, 1, '2026-03-25 15:29:54', '2026-03-25 15:29:54', 31, 9),
(66, 1, 10, 'chung', '<p>Cho đoạn lệnh sau:&nbsp;</p><p>for i in range(1,10,2):&nbsp;</p><p>&nbsp; &nbsp; print(i)&nbsp;</p><p>Trên màn hình i có các giá trị là</p>', 'single_choice', 'user', NULL, 6, 1, 1, '2026-03-25 15:48:46', '2026-03-25 15:48:46', 31, 9);
